      <button className="pc-kaccept" onClick={onAccept}>
        <Ic n="Check" />
        Admit
      </button>
      <button className="pc-kdecline" onClick={onDecline}>
        <Ic n="X2" />
        Deny
      </button>
    </div>
  );
}

